// OpenClaw Daily Ops Snapshot — message formatter
// Consumes: /internal/ops/snapshot + /internal/daily-actions
// Produces: a single Telegram-ready message string

const snapshot = $input.all()[0]?.json || {};
const actions = $input.all()[1]?.json || $input.all()[0]?.json || {};

// --- Helpers ---
function pluralize(n, singular, plural) {
  return n === 1 ? `${n} ${singular}` : `${n} ${plural || singular + 's'}`;
}

function timeSince(dateStr) {
  if (!dateStr) return null;
  const ms = Date.now() - new Date(dateStr.replace(' ', 'T') + 'Z').getTime();
  const hours = Math.floor(ms / 3600000);
  if (hours < 1) return 'hace menos de 1h';
  if (hours < 24) return `hace ${hours}h`;
  const days = Math.floor(hours / 24);
  return `hace ${days}d`;
}

// --- Date header ---
const now = new Date();
const dateStr = now.toISOString().slice(0, 10);
const dayNames = ['Dom', 'Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb'];
const dayName = dayNames[now.getDay()];

let lines = [];
lines.push(`\u{1F4CB} OpenClaw Daily Ops — ${dayName} ${dateStr}`);
lines.push('');

// --- System header from ops/snapshot ---
if (snapshot.total_leads !== undefined) {
  const parts = [
    `${snapshot.total_leads} leads`,
    `${snapshot.actionable} accionables`,
    `${snapshot.urgent} urgentes`,
  ];
  if (snapshot.claimed > 0) parts.push(`${snapshot.claimed} claimed`);
  lines.push(`\u{1F4CA} ${parts.join(' | ')}`);
  lines.push('');
}

// --- HOY PRIMERO (max 5 items, prioritized) ---
const summary = actions.summary || {};
const review = actions.top_review || [];
const clientReady = actions.top_client_ready || [];
const followup = actions.top_followup || [];
const warnings = actions.source_warnings || [];

let hoyItems = [];

// Priority 1: urgent review items (alert=true)
for (const item of review) {
  if (item.alert && hoyItems.length < 5) {
    hoyItems.push(`\u{1F6A8} #${item.lead_id} ${item.name} — score ${item.score} — REVISAR URGENTE`);
  }
}

// Priority 2: client-ready leads (highest value action)
for (const item of clientReady) {
  if (hoyItems.length < 5) {
    hoyItems.push(`\u{1F4E4} #${item.lead_id} ${item.name} — score ${item.score} — ENVIAR A CLIENTE`);
  }
}

// Priority 3: followup not recently contacted (stale)
for (const item of followup) {
  if (!item.recently_contacted && hoyItems.length < 5) {
    const attempts = item.contact_attempts_count || 0;
    hoyItems.push(`\u{1F4DE} #${item.lead_id} ${item.name} — score ${item.score} — ${attempts} intentos — SIN CONTACTO RECIENTE`);
  }
}

if (hoyItems.length > 0) {
  lines.push(`\u{1F3AF} HOY PRIMERO`);
  for (const item of hoyItems) {
    lines.push(`  ${item}`);
  }
  lines.push('');
}

// --- REVISAR ---
if (review.length > 0) {
  lines.push(`\u{1F50D} REVISAR (${summary.pending_review} pendientes)`);
  for (const item of review) {
    const alertMark = item.alert ? ' \u26A0\uFE0F' : '';
    lines.push(`  \u2022 #${item.lead_id} ${item.name} — score ${item.score} — ${item.next_action}${alertMark}`);
  }
  lines.push('');
}

// --- LISTOS PARA ENVIAR ---
if (clientReady.length > 0) {
  lines.push(`\u{1F4E4} LISTOS PARA ENVIAR (${summary.client_ready})`);
  for (const item of clientReady) {
    lines.push(`  \u2022 #${item.lead_id} ${item.name} — score ${item.score}`);
  }
  lines.push('');
}

// --- FOLLOW-UP ---
if (followup.length > 0) {
  lines.push(`\u{1F4DE} FOLLOW-UP (${summary.followup_candidates} pendientes)`);
  for (const item of followup) {
    const attempts = item.contact_attempts_count || 0;
    let contactInfo;
    if (attempts === 0) {
      contactInfo = 'sin contactar';
    } else {
      const ago = timeSince(item.last_contacted_at);
      contactInfo = `${attempts} intentos — ${ago}`;
      if (item.recently_contacted) contactInfo += ' \u2705';
    }
    lines.push(`  \u2022 #${item.lead_id} ${item.name} — score ${item.score} — ${contactInfo}`);
  }
  lines.push('');
}

// --- ALERTAS DE FUENTE ---
if (warnings.length > 0) {
  lines.push(`\u26A0\uFE0F ALERTAS DE FUENTE`);
  for (const w of warnings) {
    lines.push(`  \u2022 ${w.source} — ${w.recommendation} — ${w.rationale}`);
  }
  lines.push('');
}

// --- Empty state ---
if (review.length === 0 && clientReady.length === 0 && followup.length === 0 && warnings.length === 0) {
  lines.push(`\u2705 Sin acciones pendientes hoy.`);
  lines.push('');
}

// --- Footer ---
lines.push(`Generado: ${actions.generated_at || now.toISOString()}`);

return [{ json: { text: lines.join('\n') } }];
